const crypto = require('crypto');

const data = $input.first().json;
const stripeSignature = data.headers?.['stripe-signature'];
const rawBody = data.rawBody;

const webhookSecret = 'REPLACE_WITH_STRIPE_WEBHOOK_SIGNING_SECRET';

if (!stripeSignature) throw new Error('Missing stripe-signature header — possible non-Stripe request');
if (!rawBody) throw new Error('Raw body unavailable — ensure rawBody option is enabled on the Webhook node');

const elements = stripeSignature.split(',');
const timestampEl = elements.find(e => e.startsWith('t='));
const sigEl = elements.find(e => e.startsWith('v1='));

if (!timestampEl || !sigEl) throw new Error('Malformed stripe-signature header');

const timestamp = timestampEl.split('=')[1];
const signature = sigEl.split('=')[1];

const signedPayload = timestamp + '.' + rawBody;
const expectedSig = crypto
  .createHmac('sha256', webhookSecret)
  .update(signedPayload, 'utf8')
  .digest('hex');

if (expectedSig !== signature) throw new Error('Stripe signature verification failed — request rejected');

const tolerance = 300;
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > tolerance) {
  throw new Error('Stripe webhook timestamp expired — possible replay attack');
}

return $input.all();

const event = $input.first().json.body;
const session = event.data?.object;

if (!session) throw new Error('No session object in Stripe webhook payload. Keys received: ' + JSON.stringify(Object.keys($input.first().json)));

const fullName = session.customer_details?.name || 'Athlete';
const firstName = fullName.split(' ')[0];
const customerEmail = session.customer_details?.email;
const customerPhone = session.customer_details?.phone;
const amountTotal = session.amount_total;
const stripePaymentId = session.payment_intent;

// IMPORTANT: Amounts are in cents. Update after Eric creates the Stripe payment links.
const packageMap = {
  // Group session packages — booking handled at /book page after purchase
  11000: { type: 'group-4pack',    displayType: 'Group Training 4-Pack',  sessions: 4,    sessionType: 'group' },
  20000: { type: 'group-8pack',    displayType: 'Group Training 8-Pack',  sessions: 8,    sessionType: 'group' },
  15000: { type: 'membership',     displayType: 'Monthly Membership',     sessions: null, sessionType: 'group' },
  25000: { type: 'summer-special', displayType: 'Summer Special',         sessions: null, sessionType: 'group' },
  // 1:1 and team packages — scheduling via Calendly after purchase
  40000:  { type: '1on1-5pack',  displayType: '1:1 Training',  sessions: 5,  sessionType: 'calendly', calendlyUrl: 'https://calendly.com/coachcooper-mytrenches/1-1-package-session' },
  75000:  { type: '1on1-10pack', displayType: '1:1 Training',  sessions: 10, sessionType: 'calendly', calendlyUrl: 'https://calendly.com/coachcooper-mytrenches/1-1-package-session' },
  125000: { type: 'team-5pack',  displayType: 'Team Training', sessions: 5,  sessionType: 'calendly', calendlyUrl: 'https://calendly.com/coachcooper-mytrenches/team-training-package-session' },
  200000: { type: 'team-10pack', displayType: 'Team Training', sessions: 10, sessionType: 'calendly', calendlyUrl: 'https://calendly.com/coachcooper-mytrenches/team-training-package-session' }
};

const pkg = packageMap[amountTotal];
if (!pkg) throw new Error('Unrecognized purchase amount: ' + amountTotal + ' cents. Add it to packageMap.');

const bookingUrl = 'https://blocksmiths.mytrenches.com/book';

// Write group packages to Supabase so customers can redeem sessions at /book
if (pkg.sessionType === 'group') {
  try {
    const supabaseUrl = 'https://vyvxvpxnhihlbhbvjwxy.supabase.co';
    const supabaseKey = 'REPLACE_WITH_SUPABASE_SERVICE_ROLE_KEY';

    let validThrough = null;
    if (pkg.type === 'membership') {
      const now = new Date();
      const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);
      validThrough = endOfMonth.toISOString().split('T')[0];
    } else if (pkg.type === 'summer-special') {
      validThrough = '2026-07-31';
    }

    await fetch(supabaseUrl + '/rest/v1/blocksmiths_packages', {
      method: 'POST',
      headers: {
        'apikey': supabaseKey,
        'Authorization': 'Bearer ' + supabaseKey,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({
        customer_email: customerEmail,
        customer_name: fullName,
        package_type: pkg.type,
        sessions_total: pkg.sessions,
        sessions_remaining: pkg.sessions,
        valid_through: validThrough,
        stripe_payment_id: stripePaymentId
      })
    });
  } catch (e) {
    console.error('Supabase write failed:', e.message);
    // Continue — email still sends even if Supabase write fails
  }
}

let emailContent;
if (pkg.sessionType === 'group') {
  const sessionsLine = pkg.sessions
    ? 'You have ' + pkg.sessions + ' group training sessions locked in.'
    : 'You have unlimited group training sessions locked in.';
  emailContent = 'Write a welcome email for ' + firstName + ', who just purchased a ' + pkg.displayType + ' from Blocksmiths. Follow this template closely:\n\n' + firstName + ',\n\nPayment confirmed. ' + sessionsLine + '\n\nUse the link below to pick your sessions and lock them in.\n\n' + bookingUrl + '\n\nSessions run Tue/Fri at 5:30 PM. Show up early, bring water, wear cleats.\n\nCoach Cooper\nBlocksmiths\ncoachcooper@mytrenches.com\n\nReturn only the email body. No subject line. No explanation. No additions.';
} else {
  emailContent = 'Write a welcome email for ' + firstName + ', who just bought a ' + pkg.sessions + '-session ' + pkg.displayType + ' package from Blocksmiths. Follow this template closely. 90% identical, one or two sentences can vary slightly to feel natural:\n\n' + firstName + ',\n\nPayment confirmed. You have ' + pkg.sessions + ' ' + pkg.displayType + ' sessions locked in.\n\nUse the link below to book your first one. Pick a time that works and come ready. We do not waste reps.\n\n' + pkg.calendlyUrl + '\n\nSessions are 60 minutes. Show up early, bring water, wear cleats.\n\nCoach Cooper\nBlocksmiths\ncoachcooper@mytrenches.com\n\nReturn only the email body. No subject line. No explanation. No additions.';
}

const claudeBody = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 400,
  system: 'You are Coach Eric Cooper, founder of Blocksmiths, a youth football training company specializing in offensive and defensive line development. Write like a coach: direct, confident, no wasted words. Never use: I wanted to reach out, I hope this finds you well, excited to, thrilled, journey, empower, looking forward to working with you, do not hesitate to reach out, please feel free, or anything that sounds like a marketing template. No motivational filler. Every sentence does a job.',
  messages: [
    {
      role: 'user',
      content: emailContent
    }
  ]
};

const smsUrl = pkg.sessionType === 'group' ? bookingUrl : pkg.calendlyUrl;
const smsMessage = pkg.sessionType === 'group'
  ? firstName + ' - Blocksmiths package confirmed. Select your sessions here: ' + smsUrl + ' Reply STOP to opt out.'
  : firstName + ' - Blocksmiths package confirmed. ' + pkg.sessions + ' ' + pkg.displayType + ' sessions locked in. Book here: ' + smsUrl + ' Reply STOP to opt out.';

return [{
  json: {
    firstName,
    customerEmail,
    customerPhone,
    packageType: pkg.type,
    sessionCount: pkg.sessions,
    calendlyUrl: pkg.calendlyUrl,
    smsMessage,
    claudeBody: JSON.stringify(claudeBody)
  }
}];
